<style>
#bootcamp-anim {
    clear: both;
    height: 280px;
}

#bootcamp-anim svg {
    display: block;
    max-width: 100%;
    height: auto;
}

#bootcamp-anim .bootcamp-anim__stage {
    display: flex;
    align-items: flex-end;
    justify-content: space-between;
    gap: 8px;
    height: 100%;
    max-width: 900px;
    margin: 0 auto;
}

#bootcamp-anim .bootcamp-anim__sherlock {
    flex: 0 0 220px;
    max-width: 220px;
	position: relative;
	top: -50px;
}

#bootcamp-anim .bootcamp-anim__footsteps {
    flex: 1 1 auto;
    padding-bottom: 36px;
	position: relative;
	top: -90px;
}

#bootcamp-anim #bootcamp-footsteps {
    max-width: 82%;
    margin-left: 3rem;
}

#bootcamp-sherlock {
    overflow: visible;
    animation: bootcampSherlockIn 1s ease-in-out forwards;
}

#bootcamp-footsteps > g > g {
    opacity: 0;
    transform-box: fill-box;
    transform-origin: center;
    animation: bootcampFootstepIn 0.45s ease-in-out forwards;
}

#bootcamp-footsteps > g > g:nth-of-type(1) {
    animation-delay: 1.18s;
}

#bootcamp-footsteps > g > g:nth-of-type(2) {
    animation-delay: 0.95s;
}

#bootcamp-footsteps > g > g:nth-of-type(3) {
    animation-delay: 1.64s;
}

#bootcamp-footsteps > g > g:nth-of-type(4) {
    animation-delay: 1.41s;
}

#bootcamp-footsteps > g > g:nth-of-type(5) {
    animation-delay: 1.87s;
}

#bootcamp-footsteps > g > g:nth-of-type(6) {
    animation-delay: 2.1s;
}

#bootcamp-footsteps > g > g:nth-of-type(7) {
    animation-delay: 2.33s;
}

@keyframes bootcampSherlockIn {
    from {
        opacity: 0;
        transform: translateX(-36px);
    }

    to {
        opacity: 1;
        transform: translateX(0);
    }
}

@keyframes bootcampFootstepIn {
    from {
        opacity: 0;
        transform: translateX(-10px) scale(0.96);
    }

    to {
        opacity: 1;
        transform: translateX(0) scale(1);
    }
}

@media screen and (max-width: 768px) {
    #bootcamp-anim {
        height: auto;
    }

    #bootcamp-anim .bootcamp-anim__stage {
        gap: 12px;
        align-items: center;
    }

    #bootcamp-anim .bootcamp-anim__sherlock {
        flex-basis: 110px;
        max-width: 110px;
		top: -80px;
    }

    #bootcamp-anim .bootcamp-anim__footsteps {
        padding-bottom: 8px;
		top: -50px;
    }

    #bootcamp-anim #bootcamp-footsteps {
        max-width: 88%;
    }
}
</style>
